<?php namespace App\Models\Sales; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\SoftDeletes; class SalesOrder extends Model { use SoftDeletes; protected $keyType='string'; public $incrementing=false; protected $fillable=['order_number','created_by','status','subtotal','tax','total','metadata','approved_order_id','version','parent_id']; public function isImmutable(): bool { return in_array($this->status, ['SUBMITTED','UNDER_REVIEW','APPROVED','REJECTED']); } }
